import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. KURUMSAL ARAYÜZ AYARLARI ---st.set_page_config(    page_title="Focus AI | Master Coach ERP",     layout="wide",     initial_sidebar_state="expanded")# --- 2. STRATEJİK VERİTABANI (MÜFREDAT & REHBERLİK) ---MÜFREDAT = {    "TYT Matematik": {"Problemler": 12, "Sayılar": 3, "Geometri": 10},    "AYT Matematik": {"Türev": 4, "İntegral": 4, "Trigonometri": 4, "Logaritma": 2},    "TYT Türkçe": {"Paragraf": 26, "Dil Bilgisi": 7},    "AYT Edebiyat": {"Divan Edebiyatı": 5, "Cumhuriyet Dönemi": 4},    "AYT Fen": {"Sistemler": 4, "Modern Fizik": 2, "Organik Kimya": 3}}REHBERLIK_SORULARI = {    "VAK Öğrenme Stilleri Testi": [        "Ders dinlerken önemli yerlerin altını çizmek veya not tutmak hoşuma gider.",        "Bir konuyu anlamak için şema, grafik veya resimlere bakmayı tercih ederim.",        "Anlatılanları dinlerken ritim tutmak veya bir şeylerle oynamak beni rahatlatır.",        "Sözlü talimatlar yerine yazılı talimatları takip etmeyi daha kolay bulurum.",        "Bir şeyi öğrenirken onu denemek ve dokunmak benim için kritiktir."    ],    "Sınav Kaygısı Ölçeği": [        "Sınav sırasında ellerimin titrediğini veya terlediğini hissederim.",        "Sınavdan önceki gece uyumakta ciddi zorluk çekerim.",        "Sınav anında 'bildiklerimi unutacağım' korkusu tüm zihnimi kaplar.",        "Sınav sonuçları açıklandığında kendimi yetersiz hissetmekten korkarım.",        "Zamanın yetmeyeceği düşüncesi sınav anında beni panikletir."    ]}# --- 3. MERKEZİ HAFIZA (SESSION STATE) ---for key in ['ogrenciler', 'program', 'video_odevler', 'test_sonuclari']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Alan", "Veli Tel"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Durum", "Kaynak"])        elif key == 'video_odevler':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Başlık", "Link", "Durum"])        elif key == 'test_sonuclari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Test Adı", "Skor"])        else:            st.session_state[key] = pd.DataFrame()# --- 4. NAVİGASYON ---st.sidebar.title("🎯 Focus AI v7.7")st.sidebar.image("https://img.icons8.com/fluency/96/video-conference.png", width=80)role = st.sidebar.radio("SİSTEM PANELİ", ["👨‍🏫 KOÇLUK & YÖNETİM", "🎓 ÖĞRENCİ PANELİ"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Kaydı Yok"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇLUK & YÖNETİM PANELİ# ==========================================if role == "👨‍🏫 KOÇLUK & YÖNETİM":    st.title("🏛️ Bostanlı Çözüm VIP: Yönetim Merkezi")    tabs = st.tabs(["👤 Kayıt & Rehber", "📺 Video & Ödev Gönder", "🧠 Rehberlik Analizi", "📊 Akademik Radar"])    with tabs[0]:        st.subheader("👤 Öğrenci ve Veli Kaydı")        with st.form("kayit_f"):            c1, c2 = st.columns(2)            n_ad = c1.text_input("Öğrenci Ad Soyad")            n_tel = c2.text_input("Veli Tel (905...)")            n_alan = c1.selectbox("Alan", ["Sayısal", "EA", "Sözel"])            if st.form_submit_button("Sisteme Dahil Et"):                yeni_o = pd.DataFrame([[n_ad, n_alan, n_tel]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.success(f"{n_ad} eklendi!")                st.rerun()        st.dataframe(st.session_state.ogrenciler, use_container_width=True)    with tabs[1]:        st.subheader("📤 İçerik Atama Merkezi")        col_v1, col_v2 = st.columns(2)        with col_v1:            st.write("#### 📺 YouTube Video Playlist Ata")            with st.form("video_form"):                v_o = st.selectbox("Hedef Öğrenci", ogrenci_listesi, key="v_koc")                v_baslik = st.text_input("Video Başlığı")                v_url = st.text_input("YouTube URL")                if st.form_submit_button("Gönder"):                    if v_o != "Öğrenci Kaydı Yok":                        yeni_v = pd.DataFrame([[v_o, v_baslik, v_url, "İzlenmedi"]], columns=st.session_state.video_odevler.columns)                        st.session_state.video_odevler = pd.concat([st.session_state.video_odevler, yeni_v], ignore_index=True)                        st.success("Video gönderildi!")        with col_v2:            st.write("#### 📚 Müfredat Görevi Ata")            with st.form("odev_form"):                o_o = st.selectbox("Hedef Öğrenci", ogrenci_listesi, key="o_koc")                o_d = st.selectbox("Ders", list(MÜFREDAT.keys()))                o_k = st.multiselect("Konu(lar)", list(MÜFREDAT[o_d].keys()))                if st.form_submit_button("Ödevleri Tanımla"):                    for k in o_k:                        yeni_p = pd.DataFrame([[o_o, o_d, k, "Bekliyor", "Focus AI"]], columns=st.session_state.program.columns)                        st.session_state.program = pd.concat([st.session_state.program, yeni_p], ignore_index=True)                    st.success("Görevler iletildi!")    with tabs[2]:        st.subheader("🧠 PDR ve Rehberlik Test Analizi")        if not st.session_state.test_sonuclari.empty:            st.dataframe(st.session_state.test_sonuclari, use_container_width=True)            # Grafikleştirme            fig_pdr = px.bar(st.session_state.test_sonuclari, x="Öğrenci", y="Skor", color="Test Adı", barmode="group", title="Öğrenci Rehberlik Puanları")            st.plotly_chart(fig_pdr, use_container_width=True)        else:            st.info("Henüz tamamlanmış bir rehberlik testi bulunmuyor.")    with tabs[3]:        st.subheader("🕸️ Gelişim Radarı")        fig = go.Figure(data=go.Scatterpolar(r=[80, 70, 90, 65, 85], theta=['Akademik', 'Odak', 'Hız', 'Mental', 'Düzen'], fill='toself'))        st.plotly_chart(fig, use_container_width=True)# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ PANELİ# ==========================================else:    st.title("🎓 Öğrenci Gelişim Portalı")    p_tabs = st.tabs(["📅 Görevlerim", "📺 Videolarım", "🧠 Rehberlik Testleri"])    with p_tabs[0]:        st.subheader("Sana Atanan Ödevler")        st.dataframe(st.session_state.program, use_container_width=True)    with p_tabs[1]:        st.subheader("📺 İzlenecek Videolar")        if not st.session_state.video_odevler.empty:            for i, r in st.session_state.video_odevler.iterrows():                st.info(f"🎥 **{r['Başlık']}**")                st.link_button("Videoyu İzlemek İçin Tıkla", r['Link'])        else:            st.write("Henüz video atanmamış.")    with p_tabs[2]:        st.subheader("🧠 Rehberlik Testini Çöz")        t_sec = st.selectbox("Bir Test Seç ve Başla", list(REHBERLIK_SORULARI.keys()))                # Test Uygulama Formu        st.write(f"### {t_sec}")        st.info("Lütfen aşağıdaki ifadelere ne kadar katıldığını belirt.")                test_skor = 0        with st.form("pdr_test_form"):            for q in REHBERLIK_SORULARI[t_sec]:                cevap = st.select_slider(q, options=["Hiç", "Az", "Orta", "Çok", "Tamamen"], value="Orta")                # Puanlama mantığı                puan_haritasi = {"Hiç": 0, "Az": 5, "Orta": 10, "Çok": 15, "Tamamen": 20}                test_skor += puan_haritasi[cevap]                        o_ad_input = st.selectbox("İsmini Onayla", ogrenci_listesi)                        if st.form_submit_button("Testi Bitir ve Koçuna Gönder"):                if o_ad_input != "Öğrenci Kaydı Yok":                    yeni_test_sonuc = pd.DataFrame([[datetime.now().strftime("%d/%m/%Y"), o_ad_input, t_sec, test_skor]],                                                    columns=st.session_state.test_sonuclari.columns)                    st.session_state.test_sonuclari = pd.concat([st.session_state.test_sonuclari, yeni_test_sonuc], ignore_index=True)                    st.balloons()                    st.success(f"Tebrikler {o_ad_input}! Testin başarıyla koçuna iletildi.")